        _statusStrip.RenderMode = ToolStripRenderMode.ManagerRenderMode;
        Controls.Add(_statusStrip);
    }

    // .NET 9 breaking change: DropDownControl now throws ArgumentNullException
    // when passed null. Always guard with a null check.
    public void ShowDropDown(IWindowsFormsEditorService editorService, Control control)
    {
        if (control is not null)
        {
            editorService.DropDownControl(control);
        }
    }

    // .NET 9 breaking change: Use LibraryImport (source-generated) instead of
    // DllImport for better AOT compatibility and trimming support.
    [LibraryImport("user32.dll")]
    [return: MarshalAs(UnmanagedType.Bool)]
    internal static partial bool ShowWindow(IntPtr hWnd, int nCmdShow);

    [LibraryImport("user32.dll", SetLastError = true)]
    internal static partial IntPtr FindWindowW(
        [MarshalAs(UnmanagedType.LPWStr)] string lpClassName,
        [MarshalAs(UnmanagedType.LPWStr)] string lpWindowName);
